import Vue  from 'vue'
import Vuex from 'vuex'
import { getTimeString } from '@/utils/imageUtils'

Vue.use(Vuex)

export default new Vuex.Store({
  state: {
    // 图片相关
    images: [],           // 多张图片列表

    // 分析状态
    isAnalyzing:  false,
    uploadProgress: 0,

    // 结果
    results: null,        // 批量分析结果

    // 系统日志
    logs: [],

    // 模型服务状态
    serviceOnline: null   // null=未知, true=在线, false=离线
  },

  getters: {
    hasImages:      state => state.images.length > 0,
    imageCount:     state => state.images.length,
    hasResults:     state => state.results !== null,
    totalPigs:      state => state.results?.total_pigs ?? null,
    recentLogs:     state => state.logs.slice(0, 30)
  },

  mutations: {
    SET_IMAGES(state, images) {
      state.images = images
      state.results = null   // 清除旧结果
    },
    ADD_IMAGE(state, image) {
      state.images.push(image)
      state.results = null   // 清除旧结果
    },
    REMOVE_IMAGE(state, index) {
      state.images.splice(index, 1)
      if (state.images.length === 0) {
        state.results = null   // 清除旧结果
      }
    },
    CLEAR_IMAGES(state) {
      state.images = []
      state.results = null
      state.uploadProgress = 0
    },
    SET_ANALYZING(state, val) {
      state.isAnalyzing = val
    },
    SET_PROGRESS(state, val) {
      state.uploadProgress = val
    },
    SET_RESULTS(state, results) {
      state.results = results
    },
    ADD_LOG(state, { msg, type = 'info' }) {
      state.logs.unshift({ id: Date.now(), time: getTimeString(), msg, type })
      if (state.logs.length > 50) state.logs.pop()
    },
    CLEAR_LOGS(state) {
      state.logs = []
    },
    SET_SERVICE_STATUS(state, online) {
      state.serviceOnline = online
    }
  },

  actions: {
    addLog({ commit }, payload) {
      commit('ADD_LOG', typeof payload === 'string' ? { msg: payload } : payload)
    }
  }
})
